// import React from 'react'
import { useState } from 'react';

const products = [
  {
    id: 1,
    name: "Laptop",
    category: "Electronics",
    price: 50000
  },
  {
    id: 2,
    name: "T-Shirt",
    category: "Clothing",
    price: 1200
  },
  {
    id: 3,
    name: "Mobile",
    category: "Electronics",
    price: 30000
  },
  {
    id: 4,
    name: "Jeans",
    category: "Clothing",
    price: 2000
  }
];


function App() {

  const [electronics, setElectronics] = useState(false);
  const [clothing, setClothing] = useState(false);

  let filteredproducts = products;

  if (electronics && !clothing) {
    filteredproducts = products.filter((obj) => obj.category === "Electronics");
  }

  else if (clothing && !electronics) {
    filteredproducts = products.filter((obj) => obj.category === "Clothing");

  }

  return (
    <>

      <h1>Product Category Filter</h1>
      Electronics
      <input type="checkbox"
        checked={electronics}
        onChange={(e) => setElectronics(e.target.checked)}
      />

      Clothing
      <input type="checkbox"
        checked={clothing}
        onChange={(e) => setClothing(e.target.checked)}
      />
      <table border="1" cellPadding={10} cellSpacing={5}>
        <thead>
          <tr>
            <td>ID</td>
            <td>Name</td>
            <td>Category</td>
            <td>Price</td>
          </tr>
        </thead>

        <tbody>

          {filteredproducts.map((item) => {
            return (
              <tr key={item.id}>
                <td>{item.id}</td>
                <td>{item.name}</td>
                <td>{item.category}</td>
                <td>{item.price}</td>
              </tr>
            )
          })
          }

        </tbody>

      </table>

    </>
  )
}

export default App